4.5 Running Example Setup (Assume W Already Exists)
Below, I create a toy setting with 50 units and several candidate matrices. The focus is not how to derive these matrices from maps, but what happens once you choose one.

set.seed(2026)

n &lt;- 50
policy_pressure &lt;- as.numeric(scale(rnorm(n)))
fiscal_capacity &lt;- as.numeric(scale(rnorm(n)))

# Helper: row-standardize while keeping zero rows as zero
row_standardize &lt;- function(W) {
  rs &lt;- rowSums(W)
  W_std &lt;- W
  for (i in seq_len(nrow(W))) {
    if (rs[i] &gt; 0) {
      W_std[i, ] &lt;- W[i, ] / rs[i]
    }
  }
  W_std
}

# Candidate 1: symmetric local chain (i connected to i-1 and i+1)
W_sym_local &lt;- matrix(0, n, n)
for (i in 1:n) {
  if (i &gt; 1) W_sym_local[i, i - 1] &lt;- 1
  if (i &lt; n) W_sym_local[i, i + 1] &lt;- 1
}
W_sym_local &lt;- row_standardize(W_sym_local)

# Candidate 2: symmetric denser links (two-step neighbors)
W_sym_dense &lt;- matrix(0, n, n)
for (i in 1:n) {
  for (j in 1:n) {
    if (i != j && abs(i - j) &lt;= 2) W_sym_dense[i, j] &lt;- 1
  }
}
W_sym_dense &lt;- row_standardize(W_sym_dense)

# Candidate 3: asymmetric forward links (only from lower index to higher index)
W_asym_forward &lt;- matrix(0, n, n)
for (i in 1:n) {
  if (i &gt; 1) W_asym_forward[i, i - 1] &lt;- 1
  if (i &gt; 2) W_asym_forward[i, i - 2] &lt;- 0.5
}
W_asym_forward &lt;- row_standardize(W_asym_forward)

# Candidate 4: asymmetric hub matrix (few senders influence many)
W_asym_hub &lt;- matrix(0, n, n)
hubs &lt;- c(5, 20, 35, 45)
for (i in 1:n) {
  if (!i %in% hubs) {
    W_asym_hub[i, hubs] &lt;- c(1.0, 0.8, 0.6, 0.4)
  }
}
W_asym_hub &lt;- row_standardize(W_asym_hub)
